async function testTransfer() {
    const [signer] = await ethers.getSigners();

    const native = new ethers.Contract(
        native_token_address,
        abi,
        signer
    );

    let tx = await native.transfer(1,  "hello word");
    console.log(tx);
    console.log("wait for response of tx");
    let rc = await tx.wait();
    console.log(rc);
    
    // Parse events from receipt
    // Expected events for transfer:
    // - RollupTransfer (RollupEventReceived)
    await parseEventsFromReceipt(rc);
}

