async function testSetMintAllowed() {
    const [signer] = await ethers.getSigners();

    const native = new ethers.Contract(
        native_token_address,
        abi,
        signer
    );

    // Minter address to set allowed for
    const minter = "0xf17f52151EbEF6C7334FAD080c5704D77216b732";

    // ElGamalToken representing allowed mint amount
    const allowed = {
        id: "20867661367025141359997234519711520825546975054166275338502659251398039765416",
        value: {
            cl_x: "2476171085597093386759793961884812823517346115888955740399768345006055337716",
            cl_y: "5569092098077601353322367652759221011752914171224427158381951555232896246558",
            cr_x: "6886446568674303645977177918186069249581604696464005957284535597425012173122",
            cr_y: "499691936632386783548951421515386269707765409535076536951782893022303490374"
        }
    };

    let tx = await native.setMintAllowed(minter, allowed);
    console.log(tx);
    console.log("wait for response of tx");
    let rc = await tx.wait();
    console.log(rc);
    
    // Parse events from receipt
    // Expected events for setMintAllowed:
    // - TokenMintAllowedUpdated (EventReceived)
    await parseEventsFromReceipt(rc);
}

